import React, {useEffect, useState} from 'react';
import { Routes, Route } from 'react-router-dom';
import { useStore } from '../modules/hook-store/store';
import {BASE_PATH_APIS} from '../utils/constants';
import {AWBGenerationSettings, DataValidation, LabelTemplate, ReverseConnector, BulkUploadAddShipment, LabelGeneration , MasterData, MasterDataTabCard} from '../modules/index';


const RouteContainer = (props) => {
    const [basePath , setBasePath] = useState('/v2/label_generation');
    const [basePathForNewSetting , setBasePathForNewSetting] = useState('/v2/new_settings/label_generation');

    const dispatch = useStore(false)[1];

    useEffect(()=>{
        
        BASE_PATH_APIS.basePathForAPIS = props.fromFCR && props.isProduction ? '/fcr':'' ;
        if(props.fromFCR){
            if(props.isProduction){
                setBasePath( "/fcr/view/reactSettings/v2/label_generation");
            } else{
                setBasePath( "/view/reactSettings/v2/label_generation");
            }

        }

    },[]);

    const updateCarrierAllocationName = (data) => {
        props.updateCarrierAllocationName(data);
    }

    const updateLabelGenerationTitle = (data) => {
        props.updateLabelGenerationTitle(data);
    }

    const settingInvokeHandler = (data) => {
        props.settingInvoke(data);
    }


    return (
        <Routes>

            <Route path={`${basePath}/v2/settings`} exact="true" element={settingInvokeHandler} />
            <Route path={`${basePath}/settings`} exact="true" element={<LabelGeneration />} />
            <Route path={`${basePath}/data_validation`} exact="true" element={<DataValidation />} />
            <Route path={`${basePath}/shipment_no_generation`} exact="true" element={<AWBGenerationSettings />} />
            <Route path={`${basePath}/carrier_allocation`} exact="true" element={<MasterData updateCarrierAllocationName = {updateCarrierAllocationName}   {...props} />} />
            <Route path={`${basePath}/carrier_allocation/master_data`} exact="true" element={<MasterDataTabCard />} />
            <Route path={`${basePath}/label_templates`} exact="true" element={<LabelTemplate />} />
            <Route path={`${basePath}/reverse_connector`} exact="true" element={<ReverseConnector />} />
            <Route path={`${basePath}/bulk_upload`} exact="true" element={<BulkUploadAddShipment updateLabelGenerationTitle = {updateLabelGenerationTitle}   {...props} />}  />


            {/* <Route path={`${basePathForNewSetting}`} exact="true" component={LabelGeneration} />
            <Route path={`${basePathForNewSetting}/data_validation`} exact="true" component={DataValidation} />
            <Route path={`${basePathForNewSetting}/shipment_no_generation`} exact="true" component={AWBGenerationSettings} />
            <Route path={`${basePathForNewSetting}/carrier_allocation`} exact="true" render={(props) => <MasterData updateCarrierAllocationName = {updateCarrierAllocationName}   {...props} />} />
            <Route path={`${basePathForNewSetting}/carrier_allocation/master_data`} exact="true" component={MasterDataTabCard} />
            <Route path={`${basePathForNewSetting}/label_templates`} exact="true" component={LabelTemplate} />
            <Route path={`${basePathForNewSetting}/reverse_connector`} exact="true" component={ReverseConnector} />
            <Route path={`${basePathForNewSetting}/bulk_upload`} exact="true" render={(props) => <BulkUploadAddShipment updateLabelGenerationTitle = {updateLabelGenerationTitle}   {...props} />}  /> */} 

        </Routes>
    )
}

export default RouteContainer;